from os import statvfs
from json import dumps


def get_metrics(path: str):
    stats = statvfs(path)

    return {
        'available': stats.f_bavail * stats.f_bsize,
        'capacity': stats.f_blocks * stats.f_bsize,
        'usage': (
            stats.f_blocks - stats.f_bfree
        ) * stats.f_bsize,
        'iNodes': stats.f_files,
        'iNodesFree': stats.f_ffree,
        'iNodesUsed': stats.f_files - stats.f_ffree,
    }


if __name__ == '__main__':
    print(dumps(
        get_metrics('/var/lib/postgresql/data')
    ))
